var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 오랫동안 숲을 헤매며 요정을 찾아 다녔습니다.","JPN":"少女は長いあいだ森の中をさまよいながら妖精をさがしました。","ENG":"The girl wandered from forest to forest, looking for the fairy.","TWN":"少女為了尋找妖精，在森林中徘徊了很久。"},"stage":{"bg":"EV_SIGMA_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그러던 중 동물들을 마주쳤죠.","JPN":"そんな中、動物たちに出会いました。","ENG":"Along the way, she met some animals.","TWN":"她在路上遇到了一些動物。"},"stage":{"bg":"EV_SIGMA_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사자도, 곰도 기운이 없어 보였어요.","JPN":"しかしライオンもクマも、どこか元気がありませんでした。","ENG":"But neither the lion nor the bear looked happy.","TWN":"但是獅子和熊都是一副有氣無力的樣子。"},"stage":{"bg":"EV_SIGMA_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"그 동물들은 사실 철창으로 된 우리에 갇힌 채 자유롭지 못했답니다.","JPN":"その動物たちは鉄檻に閉じ込められ、身動きが\\nとれない状態だったのです。","ENG":"They weren't free to move, locked up behind iron bars.","TWN":"原來那些動物都被關在鐵籠子裡。"},"stage":{"bg":"EV_SIGMA_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"동물들은 밀렵꾼에게 잡혔고, 곧 서커스에 팔려갈 처지였죠.","JPN":"動物たちは密猟者に捕まり、間もなくサーカス団に\\n売られる運命でした。","ENG":"The poacher who caught them was going to sell them to a circus troupe.","TWN":"這些動物是被偷獵者獵捕的，馬上就會被賣給馬戲團。"},"stage":{"bg":"EV_SIGMA_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"이를 안타깝게 여긴 소녀는 동물들을 풀어주기로 했습니다.","JPN":"これをかわいそうに思った少女は、動物たちを\\n解放してあげようと思いました。","ENG":"Feeling sorry for them, the girl decided to let them go.","TWN":"善良的少女決定放走那些動物。"},"stage":{"bg":"EV_SIGMA_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"어이 신참! 해체 준비는 끝났나?!","JPN":"おい、新入り！　解体の準備は済んだのか！？","ENG":"Hey, rookie! Is it ready for disassembly?","TWN":"喂，新人！準備好拆解了嗎？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"네, 작업대에 고정은 마쳤습니다. 이제 대장님만 오시면 됩니다!","JPN":"はい、作業台に固定しました。後は隊長の帰りを\\n待つだけです！","ENG":"Yes, it's been strapped to the workbench. Now all we need to do is just wait for the Captain.","TWN":"是，已經固定到工作臺上了，等隊長回來就能開始！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"그런데 정말 이런 거대한 로봇을 저희 편으로 만들 수 있는 겁니까?","JPN":"でも、本当にこんな巨大なロボットを味方に\\nつけられるんですかね？","ENG":"By the way, are you sure we can turn such a big robot to our side?","TWN":"但是真的能把這巨大的機器人改造成我方戰力嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"당연하지. 우리 대장님 이름은 단순히 기계를 좋아해서 붙은 별명이 아니거든.","JPN":"当然だ。うちの隊長のあだ名はな、単に機械好きだから\\nつけられたものではないぞ。","ENG":"Of course. The Captain isn't simply called the Machine Collector because she likes machines.","TWN":"當然，我們隊長可不是浪得虛名。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"대장님의 능력은 이런 인공지능 로봇들을 꼭두각시로 만드는데 특화돼있어.","JPN":"隊長の能力はこのような人工知能ロボットを操るのに\\n特化しているんだ。","ENG":"She specializes in turning AI robots like this into her puppets.","TWN":"隊長可以用自己的能力將這些人工智慧機器人改造成他的傀儡。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"대장님이 카운터란 얘긴 이곳에 오기 전부터 들었지만...... 정말 그런 것도 가능한 겁니까?","JPN":"隊長がカウンターだということは聞いていましたが……\\n本当にそんなことまで可能なんですか？","ENG":"I heard she's a Counter before I even joined this group, but is that really possible?","TWN":"雖然早就聽說隊長是制裁者……但真的連那種事情都做到嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"듣기론 기계를 조종하는 조그만 기생충을 부린다던데, 직접 말해주신 게 없으니 정확한 건 나도 몰라.","JPN":"噂では機械を操れる小さな寄生虫を持っているとか。\\nけど、本人から聞いたわけじゃないから実際の\\nところはわからない。","ENG":"Rumor has it that she uses tiny parasites to control machines, but I don't know if that's true. I didn't ask her.","TWN":"我聽說他能使喚操控機械的寄生蟲，我也不知道具體是怎麼做到的。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"......함선의 창고들이 전부 메카닉으로 가득하던데, 대장님은 기계를 정말 좋아하시나 보네요.","JPN":"……艦船の倉庫はメカニックだらけでしたけど、隊長は\\n本当に機械好きなんですね。","ENG":"The hold in this ship is filled with mechs. The Captain really must love machines.","TWN":"……艦船的倉庫塞滿了裝甲部隊，看來隊長真的很喜歡機械。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"글쎄. 대장님이 <color=#ffd34c>작품</color>을 개조하는 과정을 직접 보고 나면 좋아한다는 말은 어울리지 않는단 걸 너도 알게 될 거다.","JPN":"どうかな。隊長が<color=#ffd34c>コレクション</color>を改造する過程を目の当たりに\\nしたら、「好き」という言葉は適していないことがわかるだろうよ。","ENG":"I don't know. If you see her working on her <color=#ffd34c>pieces</color>, you might not say she loves them.","TWN":"未必，如果你親眼看到隊長改造<color=#ffd34c>作品</color>的過程，你就不會這麼說了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIRATE_FOX_NEW_NULL","text":{"KOREA":"네? 그게 무슨......","JPN":"はい？　それはどういう……","ENG":"Sorry? I don't understand...","TWN":"什麼？什麼意思……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_NEW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FOX_OLD_NULL","text":{"KOREA":"우왓! 뭐야, 이 충격은?","JPN":"うわっ！　なんだ、この衝撃は？","ENG":"Wah! W-what happened?","TWN":"嗚哇！怎麼回事？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이봐, 너희들!","JPN":"おい、そこのお前ら！","ENG":"Hey! You two!","TWN":"喂，你們！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};